// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract FunctionIntro {
    uint public state = 12;
    function add (uint x,uint y) external pure returns (uint){
        return x+ y;
    } 

    function sub(uint x,uint y) external  pure  returns (uint){
        return  x - y;
    }

    function viewFunctionsView() external  view returns (uint){
        return state;
    }

    function pureFunctionsNeitherReadNorWrite(uint x, uint y) external  pure returns(uint){
        return x + y;
    }
}


contract Counter {
    uint  public count;

    function inc() external {
        count += 1;
    }

    function dec() external {
        count -=1;
    }
}

// we can call other contracts by providing the address of the already deployed contract
contract CallCounter{
    function examples(address _counter) external {
        Counter(_counter).inc();
    }
}

// or we can use interface


interface ICounter {
    function count() external view returns (uint);
    function inc() external ;
}

contract CallInterface{
    uint public count;
     function examples(address _counter) external {
        ICounter(_counter).inc();
        count = ICounter(_counter).count();

    }
}


contract TestCall{
    string public  message;
    uint public x;

    event Log(string message);

    fallback() external payable {
        emit Log("Fallback was called");
     }

     receive() external payable {
        emit Log("Recieve was called");
     }

     function foo(string memory _message, uint _x) external  payable  returns (bool,uint){
        message = _message;
        x = _x;
        return (true,99);
     }
}

contract call{
    bytes public data ;
    function callFoo(address _test) external {
      (bool success,bytes memory _data)=  _test.call{value:111,gas:5555}(abi.encodeWithSignature("foo(string,uint256)","call foo",123));

    require(success,"call failed");
    data = _data;
    }

}

